chart.config_raw:
(function() {
  const ctx = document.getElementById('threatChart').getContext('2d');
  new Chart(ctx, {
    type: 'bar',
    data: {
      labels: [
        'Malicious\nDeveloper',
        'External\nAttacker',
        'Malicious\nUser',
        'Security\nFlaws'
      ],
      datasets: [
        {
          label: 'Creation phase origin',
          data: [7, 0, 0, 0],
          backgroundColor: '#ff6b6b'
        },
        {
          label: 'Deployment phase origin',
          data: [0, 1, 0, 0],
          backgroundColor: '#f6ad55'
        },
        {
          label: 'Operation phase origin',
          data: [0, 1, 4, 0],
          backgroundColor: '#4dabf7'
        },
        {
          label: 'Maintenance phase origin',
          data: [0, 0, 0, 3],
          backgroundColor: '#51cf66'
        }
      ]
    },
    options: {
      animation: false,
      responsive: true,
      maintainAspectRatio: true,
      plugins: {
        legend: {
          position: 'bottom',
          labels: {
            font: { size: 12, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
            padding: 16,
            usePointStyle: true,
            pointStyleWidth: 12
          }
        },
        tooltip: {
          callbacks: {
            label: function(context) {
              return context.dataset.label + ': ' + context.parsed.y + ' threat(s)';
            }
          }
        }
      },
      scales: {
        x: {
          stacked: true,
          grid: { display: false },
          ticks: {
            font: { size: 12, weight: '600', family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
            color: '#4a5568'
          }
        },
        y: {
          stacked: true,
          beginAtZero: true,
          max: 8,
          ticks: {
            stepSize: 1,
            font: { size: 11, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
            color: '#718096'
          },
          grid: {
            color: '#e2e8f0'
          },
          title: {
            display: true,
            text: 'Number of threat scenarios',
            font: { size: 12, family: "system-ui, -apple-system, 'Segoe UI', sans-serif" },
            color: '#718096'
          }
        }
      }
    }
  });
})();
